#include <iostream>\n#include <vector>\n#include <climits>\n\nint main() {\n  int n;\n  std::cin >> n;\n  std::vector<std::vector<int>> table(n);\n  for (int i = 0; i < n; i++) {\n    table[i].resize(n);\n    for (int j = 0; j < n; j++) {\n      std::cin >> table[i][j];\n    }\n  }\n\n  int min_dist = INT_MAX;\n  std::vector<int> answer(3);\n  for (int i = 0; i < n - 2; i++) {\n    for (int j = i + 1; j < n - 1; j++) {\n      for (int k = j + 1; k < n; k++) {\n        int first = table[i][j];\n        int second = table[i][k];\n        int third = table[j][k];\n        if (first == 0 || second == 0 || third == 0) {\n          break;\n        }\n        int dist = first + second + third;\n        min_dist = std::min(min_dist, dist);\n      }\n    }\n  }\n\n  for (int i = 0; i < n - 2; i++) {\n    for (int j = i + 1; j < n - 1; j++) {\n      for (int k = j + 1; k < n; k++) {\n        int first = table[i][j];\n        int second = table[i][k];\n        int third = table[j][k];\n        if (first == 0 || second == 0 || third == 0) {\n          break;\n        }\n        int dist = first + second + third;\n        if (dist == min_dist) {\n          std::cout << i << ' ' << j << ' ' << k << std::endl;\n          return 0;\n        }\n      }\n    }\n  }\n  return 0;\n}